import * as React from 'react';

type OversightMode = "shadow" | "checkpoint" | "recovery";
interface OversightState {
    mode: OversightMode;
    pendingCount: number;
    approvedCount: number;
    rejectedCount: number;
}
interface EscalationPayload {
    action: string;
    agent: string;
    reason: string;
    confidence: number;
    risk: "low" | "medium" | "high" | "critical";
    evidence?: Record<string, any>;
}
declare function useOversight(initialMode?: OversightMode): {
    mode: OversightMode;
    setMode: React.Dispatch<React.SetStateAction<OversightMode>>;
    queue: EscalationPayload[];
    history: (EscalationPayload & {
        status: "approved" | "rejected";
        timestamp: string;
    })[];
    state: OversightState;
    requestApproval: (payload: EscalationPayload) => Promise<boolean>;
    approve: (action: string, agent: string) => void;
    reject: (action: string, agent: string) => void;
};

export { type OversightMode, useOversight };
